"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import { z } from "zod";

import Image from "next/image";

import { sendOtp } from "@/entities/auth/api/services";
import {
  useCheckEmailExists,
  useCheckPhoneExists,
} from "@/shared/api/query-hooks/use-auth-checks";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { USER_ROLES } from "@/shared/constants";
import { authStorage } from "@/shared/lib/storage/auth-storage";
import { OtpType } from "@/shared/types/auth.types";
import { Checkbox } from "@/shared/ui/checkbox";
import { Form } from "@/shared/ui/form/form";
import { FormControl } from "@/shared/ui/form/form-control";
import { FormField } from "@/shared/ui/form/form-field";
import { FormItem } from "@/shared/ui/form/form-item";
import { FormLabel } from "@/shared/ui/form/form-label";
import { FormMessage } from "@/shared/ui/form/form-message";
import { Input } from "@/shared/ui/input";
import { toast } from "@/shared/ui/notification";
import { PhoneInput } from "@/shared/ui/phone-input";
import { Button } from "@/shared/ui/shadcn/button";

const signupSchema = z.object({
  firstName: z.string().min(2, "First name must be at least 2 characters"),
  lastName: z.string().min(1, "Last name is required"),
  email: z.string().email("Please enter a valid email"),
  phone: z.string().min(10, "Phone number must be at least 10 digits"),
  uaeResident: z.boolean(),
});

type SignupFormData = z.infer<typeof signupSchema>;

function GoogleIcon() {
  return (
    <svg
      aria-hidden="true"
      width="20"
      height="20"
      viewBox="0 0 20 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        d="M19.6 10.23c0-.68-.06-1.36-.18-2H10v3.79h5.37a4.61 4.61 0 0 1-1.99 3.01v2.5h3.22c1.88-1.73 2.96-4.28 2.96-7.3z"
        fill="#4285F4"
      />
      <path
        d="M10 20c2.7 0 4.96-.9 6.61-2.43l-3.22-2.5c-.9.6-2.04.96-3.39.96-2.61 0-4.82-1.76-5.61-4.13H1.06v2.57A9.99 9.99 0 0 0 10 20z"
        fill="#34A853"
      />
      <path
        d="M4.39 11.9A5.9 5.9 0 0 1 4.08 10c0-.66.12-1.3.31-1.9V5.53H1.06A9.99 9.99 0 0 0 0 10c0 1.61.38 3.13 1.06 4.47l3.33-2.57z"
        fill="#FBBC05"
      />
      <path
        d="M10 3.97c1.47 0 2.8.51 3.84 1.5l2.87-2.87C15 .9 12.71 0 10 0A9.99 9.99 0 0 0 1.06 5.53L4.39 8.1C5.18 5.73 7.39 3.97 10 3.97z"
        fill="#EA4335"
      />
    </svg>
  );
}

function AppleIcon() {
  return (
    <Image
      src="/new-design-images/auth/apple-logo.svg"
      alt="apple"
      width={17}
      height={20}
      className="shrink-0"
    />
  );
}

function UaePassIcon() {
  return (
    <Image
      src="/new-design-images/auth/uae-pass-logo.svg"
      alt="uae-pass"
      width={21}
      height={20}
      className="shrink-0"
    />
  );
}

const SOCIAL_BUTTONS = [
  { key: "google", Icon: GoogleIcon, label: "Google" },
  { key: "apple", Icon: AppleIcon, label: "Apple" },
  { key: "uaepass", Icon: UaePassIcon, label: "UAE Pass" },
];

export function SignupForm() {
  const router = useRouter();

  const checkEmailExists = useCheckEmailExists();
  const checkPhoneExists = useCheckPhoneExists();

  const form = useForm<SignupFormData>({
    resolver: zodResolver(signupSchema),
    defaultValues: {
      firstName: "",
      lastName: "",
      email: "",
      phone: "",
      uaeResident: false,
    },
  });

  const { isSubmitting } = form.formState;

  const onSubmit = async (data: SignupFormData) => {
    try {
      const [emailCheckResult, phoneCheckResult] = await Promise.all([
        checkEmailExists.mutateAsync(data.email),
        checkPhoneExists.mutateAsync(data.phone),
      ]);

      let hasErrors = false;

      if (emailCheckResult.exists) {
        form.setError("email", {
          type: "manual",
          message:
            "This email is already registered. Please use a different email or sign in.",
        });
        hasErrors = true;
      }

      if (phoneCheckResult.exists) {
        form.setError("phone", {
          type: "manual",
          message:
            "This phone number is already registered. Please use a different number or sign in.",
        });
        hasErrors = true;
      }

      if (hasErrors) {
        return;
      }

      const otpResponse = await sendOtp({
        email: data.email,
        phone: data.phone,
        type: OtpType.SIGN_UP,
      });

      authStorage.signup.set({
        email: data.email,
        phone: data.phone,
        firstName: data.firstName,
        lastName: data.lastName,
        role: USER_ROLES.SELLER,
        referralCode: undefined,
        devEmailOtp: otpResponse.otp,
        devPhoneOtp: otpResponse.otp,
      });

      if (otpResponse.otp) {
        toast.success("OTP Generated", {
          description: "Check the verification page for your OTP codes",
        });
      } else {
        toast.success("OTP Sent", {
          description: "Please check your email and phone for OTP codes",
        });
      }

      router.push(APP_ROUTES.AUTH.VERIFY_OTP);
    } catch {
      toast.error("Failed to Send OTP", {
        description: "Please try again later",
      });
    }
  };

  return (
    <div className="new-design flex w-full flex-col gap-8">
      {/* Header */}
      <div className="flex flex-col gap-2">
        <h1 className="font-light font-new-serif text-2xl leading-[120%]">
          Join LuxFlow
        </h1>
        <p className="text-base leading-[150%] tracking-[-0.01em]">
          Get valuations, manage your offers, and unlock liquidity for your
          luxury items.
        </p>
      </div>

      {/* Social Buttons */}
      <div className="flex flex-col gap-2 sm:flex-row">
        {SOCIAL_BUTTONS.map(({ key, Icon, label }) => (
          <button
            key={key}
            type="button"
            disabled
            className="flex h-12 w-full cursor-not-allowed items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em] opacity-70 sm:flex-1"
          >
            <Icon />
            <span className="whitespace-nowrap">{label}</span>
          </button>
        ))}
      </div>

      {/* Form Section */}
      <div className="flex flex-col gap-5">
        {/* OR Divider */}
        <div className="flex items-center gap-4">
          <div className="flex-1 border-[#D6D3D1] border-t" />
          <span className="font-bold text-[#A8A29E] text-sm tracking-[-0.01em]">
            OR
          </span>
          <div className="flex-1 border-[#D6D3D1] border-t" />
        </div>

        <Form {...form}>
          <form
            onSubmit={form.handleSubmit(onSubmit)}
            className="flex flex-col gap-5"
          >
            <div className="flex flex-col gap-2">
              {/* First Name + Last Name */}
              <div className="grid grid-cols-2 gap-2">
                <FormField
                  control={form.control}
                  name="firstName"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-normal text-sm leading-[130%]">
                        First Name
                      </FormLabel>
                      <FormControl>
                        <Input
                          placeholder="Enter your first name"
                          className="h-12 rounded-[4px] border-[#A8A29E] px-3 text-sm placeholder:text-[#A8A29E]"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={form.control}
                  name="lastName"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-normal text-sm leading-[130%]">
                        Last Name
                      </FormLabel>
                      <FormControl>
                        <Input
                          placeholder="Enter your last name"
                          className="h-12 rounded-[4px] border-[#A8A29E] px-3 text-sm placeholder:text-[#A8A29E]"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              {/* Phone Number */}
              <FormField
                control={form.control}
                name="phone"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="font-normal text-sm leading-[130%]">
                      Phone Number
                    </FormLabel>
                    <FormControl>
                      <PhoneInput
                        defaultCountryAlpha2="AE"
                        placeholder="e.g. 50-123-4567"
                        className="h-12 rounded-[4px] border-[#A8A29E]"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Email */}
              <FormField
                control={form.control}
                name="email"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="font-normal text-sm leading-[130%]">
                      Email
                    </FormLabel>
                    <FormControl>
                      <Input
                        placeholder="Enter your email"
                        type="email"
                        className="h-12 rounded-[4px] border-[#A8A29E] px-3 text-sm placeholder:text-[#A8A29E]"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* UAE Residency Checkbox */}
              <FormField
                control={form.control}
                name="uaeResident"
                render={({ field }) => (
                  <FormItem>
                    <div className="flex items-center gap-2">
                      <Checkbox
                        id="uaeResident"
                        checked={field.value}
                        onCheckedChange={field.onChange}
                        className="data-[state=checked]:border-[#021171] data-[state=checked]:bg-[#021171]"
                      />
                      <FormLabel
                        htmlFor="uaeResident"
                        className="cursor-pointer font-normal text-sm leading-[150%] tracking-[-0.01em]"
                      >
                        I confirm I reside, or have an address in UAE
                      </FormLabel>
                    </div>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            {/* OTP Notice */}
            <p className="text-sm leading-[150%] tracking-[-0.01em]">
              You will receive a <strong>one-time code</strong> to your email
              and phone to verify your profile.
            </p>

            {/* Continue Button */}
            <Button
              type="submit"
              disabled={isSubmitting}
              className="flex h-12 w-full items-center justify-center rounded-[4px] bg-[#021171] font-medium text-[#F5F3EF] text-base transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-70"
            >
              {isSubmitting ? "Sending..." : "Continue"}
            </Button>

            {/* Login link */}
            <p className="text-center text-sm leading-[150%] tracking-[-0.01em]">
              Already have an account?{" "}
              <Link
                href={APP_ROUTES.AUTH.SIGN_IN}
                className="font-semibold hover:opacity-70"
              >
                Login
              </Link>
            </p>
          </form>
        </Form>
      </div>
    </div>
  );
}

