  ACTIVE = "ACTIVE",
  INACTIVE = "INACTIVE",
}

export enum OtpType {
  SIGN_UP = "SIGN_UP",
  FORGOT_PASSWORD = "FORGOT_PASSWORD",
  BUYBACK_PERIOD_EXTENSION = "BUYBACK_PERIOD_EXTENSION",
}

export enum MediaType {
  EMAIL = "EMAIL",
  PHONE = "PHONE",
}

export enum Permission {
