34	        if (!(credentials?.email && credentials?.password)) return null;
35	
36	        try {
37	          const response = await signIn({
38	            email: credentials.email,
39	            password: credentials.password,
40	          });
41	
42	          if (
43	            response.status === "CHALLENGE" &&
44	            response.challengeName === "NEW_PASSWORD_REQUIRED"
45	          ) {
