import { createEnv } from "@t3-oss/env-nextjs";
import { nativeEnum, string } from "zod";

import { AppEnvironment } from "./app-environment";

export const ENV = createEnv({
  server: {
    NEXTAUTH_SECRET: string().min(1, "NEXTAUTH_SECRET is missed"),
    NEXTAUTH_URL: string().url().min(1, "NEXTAUTH_URL is missed"),
  },
  client: {
    NEXT_PUBLIC_APP_API_URL: string()
      .url()
      .min(1, "NEXT_PUBLIC_APP_API_URL is missed"),
    NEXT_PUBLIC_APP_URL: string().url().min(1, "NEXT_PUBLIC_APP_URL is missed"),
    NEXT_PUBLIC_CDN_URL: string().url().min(1, "NEXT_PUBLIC_CDN_URL is missed"),
    NEXT_PUBLIC_ENVIRONMENT: nativeEnum(AppEnvironment, {
      required_error: "NEXT_PUBLIC_ENVIRONMENT is missed",
      invalid_type_error: `NEXT_PUBLIC_ENVIRONMENT can be only one of: ${Object.values(AppEnvironment)}`,
    }),
    NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY: string().min(
      1,
      "NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY is missed",
    ),
  },
  experimental__runtimeEnv: {
    NEXT_PUBLIC_APP_API_URL: process.env.NEXT_PUBLIC_APP_API_URL,
    NEXT_PUBLIC_APP_URL: process.env.NEXT_PUBLIC_APP_URL,
    NEXT_PUBLIC_CDN_URL: process.env.NEXT_PUBLIC_CDN_URL,
    NEXT_PUBLIC_ENVIRONMENT: process.env.NEXT_PUBLIC_ENVIRONMENT,
    NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY:
      process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY,
  },
});

